// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"time"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/labels"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging/logfields"
	"github.com/cilium/cilium/pkg/policy/api"
	"github.com/cilium/cilium/pkg/policy/trafficdirection"
)

const (
	// auditLogMsg is the fixed message emitted for every audit log entry.
	auditLogMsg = "policy audit decision"

	// logFieldDecision is the structured log field key for the policy decision.
	logFieldDecision = "decision"

	// logFieldDstIdentity is the structured log field key for the destination identity.
	logFieldDstIdentity = "dstIdentity"

	// logFieldDerivedFromRules is the structured log field key for the rules that
	// produced this decision.
	logFieldDerivedFromRules = "derivedFromRules"

	// defaultMaxEntries is the default capacity of the in-memory audit ring buffer.
	defaultMaxEntries = 1000
)

// AuditEntry captures all fields relevant to a single policy evaluation decision.
type AuditEntry struct {
	// Timestamp is when the decision was evaluated.
	Timestamp time.Time

	// SrcIdentity is the numeric security identity of the traffic source.
	SrcIdentity identity.NumericIdentity

	// DstIdentity is the numeric security identity of the traffic destination.
	DstIdentity identity.NumericIdentity

	// TrafficDirection indicates whether the decision applies to ingress or egress traffic.
	TrafficDirection trafficdirection.TrafficDirection

	// DestPort is the destination L4 port in host byte order.
	DestPort uint16

	// Protocol is the L4 protocol (next-header) value.
	Protocol uint8

	// PolicyRevision is the revision of the policy repository at decision time.
	PolicyRevision uint64

	// Decision is the outcome of the policy evaluation.
	Decision api.Decision

	// Reason is a human-readable explanation for the decision.
	Reason string

	// DerivedFromRules lists the policy rules that produced this decision.
	DerivedFromRules labels.LabelArrayList
}

// Option is a functional option for configuring a PolicyAuditLogger.
type Option func(*PolicyAuditLogger)

// WithLevel sets the logrus level at which audit entries are emitted.
func WithLevel(level logrus.Level) Option {
	return func(l *PolicyAuditLogger) { l.level = level }
}

// WithMaxEntries sets the maximum number of entries retained in the in-memory
// ring buffer. A value of 0 disables in-memory retention entirely.
func WithMaxEntries(n int) Option {
	return func(l *PolicyAuditLogger) {
		if n < 0 {
			n = 0
		}
		l.maxEntries = n
		l.entries = make([]AuditEntry, 0, min(n, defaultMaxEntries))
	}
}

// WithEnabled controls whether the logger starts in the enabled state.
func WithEnabled(enabled bool) Option {
	return func(l *PolicyAuditLogger) { l.enabled = enabled }
}

// withLogger overrides the underlying logrus entry. Intended for unit tests.
func withLogger(entry *logrus.Entry) Option {
	return func(l *PolicyAuditLogger) { l.logger = entry }
}

// PolicyAuditLogger records structured policy evaluation decisions both to the
// Cilium log stream and to a bounded in-memory ring buffer.
//
// All exported methods are safe for concurrent use.
type PolicyAuditLogger struct {
	mu         lock.RWMutex
	enabled    bool
	level      logrus.Level
	maxEntries int
	entries    []AuditEntry
	logger     *logrus.Entry
}

// NewPolicyAuditLogger returns a new PolicyAuditLogger with sensible defaults.
// Audit logging is disabled by default; call Enable or pass WithEnabled(true).
func NewPolicyAuditLogger(opts ...Option) *PolicyAuditLogger {
	l := &PolicyAuditLogger{
		enabled:    false,
		level:      logrus.InfoLevel,
		maxEntries: defaultMaxEntries,
		entries:    make([]AuditEntry, 0, defaultMaxEntries),
		logger:     log,
	}
	for _, o := range opts {
		o(l)
	}
	return l
}

// Enable activates audit logging.
func (l *PolicyAuditLogger) Enable() {
	l.mu.Lock()
	l.enabled = true
	l.mu.Unlock()
}

// Disable deactivates audit logging. Entries already buffered are preserved.
func (l *PolicyAuditLogger) Disable() {
	l.mu.Lock()
	l.enabled = false
	l.mu.Unlock()
}

// IsEnabled reports whether audit logging is currently active.
func (l *PolicyAuditLogger) IsEnabled() bool {
	l.mu.RLock()
	v := l.enabled
	l.mu.RUnlock()
	return v
}

// SetLevel changes the logrus level used for subsequent audit log entries.
func (l *PolicyAuditLogger) SetLevel(level logrus.Level) {
	l.mu.Lock()
	l.level = level
	l.mu.Unlock()
}

// LogDecision records a policy evaluation decision. If the logger is disabled
// the call is a no-op. The entry is both emitted to the structured log stream
// and appended to the in-memory ring buffer (when maxEntries > 0).
func (l *PolicyAuditLogger) LogDecision(entry AuditEntry) {
	l.mu.RLock()
	enabled := l.enabled
	level := l.level
	logger := l.logger
	l.mu.RUnlock()

	if !enabled {
		return
	}

	if entry.Timestamp.IsZero() {
		entry.Timestamp = time.Now()
	}

	fields := logrus.Fields{
		logFieldDecision:         entry.Decision.String(),
		logfields.Identity:       entry.SrcIdentity,
		logFieldDstIdentity:      entry.DstIdentity,
		logfields.TrafficDirection: entry.TrafficDirection.String(),
		logfields.Port:           entry.DestPort,
		logfields.Protocol:       entry.Protocol,
		logfields.PolicyRevision: entry.PolicyRevision,
	}
	if entry.Reason != "" {
		fields[logfields.Reason] = entry.Reason
	}
	if len(entry.DerivedFromRules) > 0 {
		fields[logFieldDerivedFromRules] = entry.DerivedFromRules
	}

	scopedLog := logger.WithFields(fields)
	switch level {
	case logrus.DebugLevel, logrus.TraceLevel:
		scopedLog.Debug(auditLogMsg)
	case logrus.WarnLevel:
		scopedLog.Warning(auditLogMsg)
	case logrus.ErrorLevel:
		scopedLog.Error(auditLogMsg)
	default:
		scopedLog.Info(auditLogMsg)
	}

	l.mu.Lock()
	if l.maxEntries > 0 {
		if len(l.entries) >= l.maxEntries {
			// Ring-buffer eviction: overwrite in place to avoid allocation.
			copy(l.entries, l.entries[1:])
			l.entries[len(l.entries)-1] = entry
		} else {
			l.entries = append(l.entries, entry)
		}
	}
	l.mu.Unlock()
}

// RecentEntries returns a snapshot copy of the in-memory audit ring buffer,
// ordered from oldest to newest. The caller may freely modify the returned slice.
func (l *PolicyAuditLogger) RecentEntries() []AuditEntry {
	l.mu.RLock()
	defer l.mu.RUnlock()
	if len(l.entries) == 0 {
		return nil
	}
	out := make([]AuditEntry, len(l.entries))
	copy(out, l.entries)
	return out
}

// Flush discards all entries currently held in the in-memory ring buffer.
func (l *PolicyAuditLogger) Flush() {
	l.mu.Lock()
	l.entries = l.entries[:0]
	l.mu.Unlock()
}

