package policy

import (
	"bytes"
	"strings"
	"sync"
	"testing"
	"time"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/labels"
	"github.com/cilium/cilium/pkg/policy/api"
	"github.com/cilium/cilium/pkg/policy/trafficdirection"
)

// newTestLogger returns a logrus Entry that writes JSON to buf, enabling tests
// to assert on emitted log fields without touching the global logger.
func newTestLogger(buf *bytes.Buffer) *logrus.Entry {
	l := logrus.New()
	l.SetOutput(buf)
	l.SetFormatter(&logrus.JSONFormatter{})
	l.SetLevel(logrus.TraceLevel) // capture everything
	return logrus.NewEntry(l)
}

// sampleEntry returns a fully-populated AuditEntry for use in tests.
func sampleEntry() AuditEntry {
	return AuditEntry{
		Timestamp:        time.Date(2024, 1, 15, 12, 0, 0, 0, time.UTC),
		SrcIdentity:      identity.NumericIdentity(100),
		DstIdentity:      identity.NumericIdentity(200),
		TrafficDirection: trafficdirection.Ingress,
		DestPort:         443,
		Protocol:         6, // TCP
		PolicyRevision:   42,
		Decision:         api.Allowed,
		Reason:           "matched ingress allow rule",
		DerivedFromRules: labels.LabelArrayList{
			labels.LabelArray{labels.NewLabel("k8s:app", "frontend", labels.LabelSourceK8s)},
		},
	}
}

// --- Construction & defaults ---

func TestNewPolicyAuditLoggerDefaults(t *testing.T) {
	l := NewPolicyAuditLogger()

	assert.False(t, l.IsEnabled(), "logger should be disabled by default")
	assert.Equal(t, logrus.InfoLevel, l.level)
	assert.Equal(t, defaultMaxEntries, l.maxEntries)
	assert.Empty(t, l.RecentEntries())
	assert.NotNil(t, l.logger)
}

func TestNewPolicyAuditLoggerWithOptions(t *testing.T) {
	var buf bytes.Buffer
	entry := newTestLogger(&buf)

	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithLevel(logrus.DebugLevel),
		WithMaxEntries(50),
		withLogger(entry),
	)

	assert.True(t, l.IsEnabled())
	assert.Equal(t, logrus.DebugLevel, l.level)
	assert.Equal(t, 50, l.maxEntries)
}

func TestWithMaxEntriesNegativeClampedToZero(t *testing.T) {
	l := NewPolicyAuditLogger(WithMaxEntries(-5))
	assert.Equal(t, 0, l.maxEntries)
}

// --- Enable / Disable / IsEnabled ---

func TestEnableDisable(t *testing.T) {
	l := NewPolicyAuditLogger()
	require.False(t, l.IsEnabled())

	l.Enable()
	assert.True(t, l.IsEnabled())

	l.Disable()
	assert.False(t, l.IsEnabled())
}

func TestEnableIdempotent(t *testing.T) {
	l := NewPolicyAuditLogger()
	l.Enable()
	l.Enable()
	assert.True(t, l.IsEnabled())
}

func TestDisableIdempotent(t *testing.T) {
	l := NewPolicyAuditLogger(WithEnabled(true))
	l.Disable()
	l.Disable()
	assert.False(t, l.IsEnabled())
}

// --- SetLevel ---

func TestSetLevel(t *testing.T) {
	l := NewPolicyAuditLogger()
	assert.Equal(t, logrus.InfoLevel, l.level)

	l.SetLevel(logrus.DebugLevel)
	assert.Equal(t, logrus.DebugLevel, l.level)

	l.SetLevel(logrus.WarnLevel)
	assert.Equal(t, logrus.WarnLevel, l.level)
}

// --- LogDecision: disabled path ---

func TestLogDecisionNoOpWhenDisabled(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(withLogger(newTestLogger(&buf)))
	// logger is disabled by default

	l.LogDecision(sampleEntry())

	assert.Empty(t, l.RecentEntries(), "no entries should be buffered when disabled")
	assert.Empty(t, buf.String(), "nothing should be written to the log when disabled")
}

// --- LogDecision: enabled path ---

func TestLogDecisionBuffersEntry(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(WithEnabled(true), withLogger(newTestLogger(&buf)))

	e := sampleEntry()
	l.LogDecision(e)

	entries := l.RecentEntries()
	require.Len(t, entries, 1)
	assert.Equal(t, e.SrcIdentity, entries[0].SrcIdentity)
	assert.Equal(t, e.DstIdentity, entries[0].DstIdentity)
	assert.Equal(t, e.Decision, entries[0].Decision)
	assert.Equal(t, e.Reason, entries[0].Reason)
	assert.Equal(t, e.PolicyRevision, entries[0].PolicyRevision)
	assert.Equal(t, e.DestPort, entries[0].DestPort)
	assert.Equal(t, e.Protocol, entries[0].Protocol)
	assert.Equal(t, e.TrafficDirection, entries[0].TrafficDirection)
}

func TestLogDecisionEmitsStructuredFields(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(WithEnabled(true), withLogger(newTestLogger(&buf)))

	l.LogDecision(sampleEntry())

	out := buf.String()
	assert.Contains(t, out, auditLogMsg)
	assert.Contains(t, out, `"decision"`)
	assert.Contains(t, out, `"allowed"`)
	assert.Contains(t, out, `"identity"`)
	assert.Contains(t, out, `"dstIdentity"`)
	assert.Contains(t, out, `"trafficDirection"`)
	assert.Contains(t, out, `"port"`)
	assert.Contains(t, out, `"protocol"`)
	assert.Contains(t, out, `"policyRevision"`)
	assert.Contains(t, out, `"reason"`)
	assert.Contains(t, out, `"derivedFromRules"`)
}

func TestLogDecisionOmitsEmptyReasonAndRules(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(WithEnabled(true), withLogger(newTestLogger(&buf)))

	e := sampleEntry()
	e.Reason = ""
	e.DerivedFromRules = nil
	l.LogDecision(e)

	out := buf.String()
	assert.NotContains(t, out, `"reason"`)
	assert.NotContains(t, out, `"derivedFromRules"`)
}

func TestLogDecisionSetsTimestampWhenZero(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(WithEnabled(true), withLogger(newTestLogger(&buf)))

	e := sampleEntry()
	e.Timestamp = time.Time{} // zero value
	before := time.Now()
	l.LogDecision(e)
	after := time.Now()

	entries := l.RecentEntries()
	require.Len(t, entries, 1)
	assert.True(t, entries[0].Timestamp.After(before) || entries[0].Timestamp.Equal(before))
	assert.True(t, entries[0].Timestamp.Before(after) || entries[0].Timestamp.Equal(after))
}

func TestLogDecisionPreservesExplicitTimestamp(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(WithEnabled(true), withLogger(newTestLogger(&buf)))

	e := sampleEntry() // has explicit timestamp
	l.LogDecision(e)

	entries := l.RecentEntries()
	require.Len(t, entries, 1)
	assert.Equal(t, e.Timestamp, entries[0].Timestamp)
}

// --- LogDecision: all decision types ---

func TestLogDecisionAllDecisionTypes(t *testing.T) {
	decisions := []api.Decision{api.Allowed, api.Denied, api.Undecided}
	for _, d := range decisions {
		t.Run(d.String(), func(t *testing.T) {
			var buf bytes.Buffer
			l := NewPolicyAuditLogger(WithEnabled(true), withLogger(newTestLogger(&buf)))

			e := sampleEntry()
			e.Decision = d
			l.LogDecision(e)

			entries := l.RecentEntries()
			require.Len(t, entries, 1)
			assert.Equal(t, d, entries[0].Decision)
			assert.Contains(t, buf.String(), d.String())
		})
	}
}

// --- LogDecision: log levels ---

func TestLogDecisionAtDebugLevel(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithLevel(logrus.DebugLevel),
		withLogger(newTestLogger(&buf)),
	)
	l.LogDecision(sampleEntry())
	assert.Contains(t, buf.String(), `"level":"debug"`)
}

func TestLogDecisionAtWarnLevel(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithLevel(logrus.WarnLevel),
		withLogger(newTestLogger(&buf)),
	)
	l.LogDecision(sampleEntry())
	assert.Contains(t, buf.String(), `"level":"warning"`)
}

func TestLogDecisionAtInfoLevel(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithLevel(logrus.InfoLevel),
		withLogger(newTestLogger(&buf)),
	)
	l.LogDecision(sampleEntry())
	assert.Contains(t, buf.String(), `"level":"info"`)
}

func TestLogDecisionAtErrorLevel(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithLevel(logrus.ErrorLevel),
		withLogger(newTestLogger(&buf)),
	)
	l.LogDecision(sampleEntry())
	assert.Contains(t, buf.String(), `"level":"error"`)
}

func TestLogDecisionAtTraceLevel(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithLevel(logrus.TraceLevel),
		withLogger(newTestLogger(&buf)),
	)
	l.LogDecision(sampleEntry())
	// TraceLevel falls through to the debug branch in the switch.
	assert.Contains(t, buf.String(), `"level":"debug"`)
}

// --- LogDecision: maxEntries == 0 ---

func TestLogDecisionNoBufferingWhenMaxEntriesZero(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithMaxEntries(0),
		withLogger(newTestLogger(&buf)),
	)

	l.LogDecision(sampleEntry())

	assert.Empty(t, l.RecentEntries(), "no buffering expected when maxEntries is 0")
	assert.NotEmpty(t, buf.String(), "log output should still be emitted")
}

// --- Ring buffer eviction ---

func TestLogDecisionRingBufferEvictsOldest(t *testing.T) {
	var buf bytes.Buffer
	const max = 3
	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithMaxEntries(max),
		withLogger(newTestLogger(&buf)),
	)

	for i := 0; i < max+2; i++ {
		e := sampleEntry()
		e.PolicyRevision = uint64(i)
		l.LogDecision(e)
	}

	entries := l.RecentEntries()
	require.Len(t, entries, max)
	// Oldest entries (revision 0 and 1) should have been evicted.
	assert.Equal(t, uint64(2), entries[0].PolicyRevision)
