// --- Concurrent safety ---

func TestConcurrentLogDecision(t *testing.T) {
	var buf bytes.Buffer
	const workers = 20
	const perWorker = 50

	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithMaxEntries(workers*perWorker),
		withLogger(newTestLogger(&buf)),
	)

	var wg sync.WaitGroup
	wg.Add(workers)
	for i := 0; i < workers; i++ {
		go func(id int) {
			defer wg.Done()
			for j := 0; j < perWorker; j++ {
				e := sampleEntry()
				e.SrcIdentity = identity.NumericIdentity(id*1000 + j)
				l.LogDecision(e)
			}
		}(i)
	}
	wg.Wait()

	entries := l.RecentEntries()
	assert.Len(t, entries, workers*perWorker)
}

func TestConcurrentEnableDisable(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(WithEnabled(true), withLogger(newTestLogger(&buf)))

	var wg sync.WaitGroup
	const goroutines = 50

	// Concurrent Enable/Disable calls must not race.
	wg.Add(goroutines)
	for i := 0; i < goroutines; i++ {
		go func(i int) {
			defer wg.Done()
			if i%2 == 0 {
				l.Enable()
			} else {
				l.Disable()
			}
		}(i)
	}
	wg.Wait()

	// IsEnabled must return a consistent value without panicking.
	_ = l.IsEnabled()
}

func TestConcurrentFlushAndLog(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLogger(
		WithEnabled(true),
		WithMaxEntries(200),
		withLogger(newTestLogger(&buf)),
	)

	var wg sync.WaitGroup
	wg.Add(2)

	go func() {
		defer wg.Done()
		for i := 0; i < 100; i++ {
			l.LogDecision(sampleEntry())
		}
	}()

	go func() {
		defer wg.Done()
		for i := 0; i < 10; i++ {
			l.Flush()
		}
	}()

	wg.Wait()
	// No panic and buffer length is within bounds.
	assert.LessOrEqual(t, len(l.RecentEntries()), 200)
}
